  ('pukao-d592fc58-moex-00097', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '關於行政訴訟訴訟費用之敘述，下列何者正確？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣4,000元", "依行政訴訟法第198條為情況判決時，其訴訟費用由被告負擔", "基於行政訴訟之公益性，行政訴訟由國家負擔訴訟費用", "當事人無資力支出訴訟費用者，行政法院得依職權以裁定准予訴訟救助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00098', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '甲之外籍配偶乙向我國駐外使領館申請入臺簽證，但經調查甲、乙婚姻真實性尚有可疑之處，乃拒絕 核發簽證。依憲法法庭裁判意旨，下列敘述何者正確？', '["因入臺簽證僅外國人須申請，甲非申請人故無提起行政救濟之權利", "甲與乙僅具有事實上或情感上之利害關係，故甲不得提起行政救濟", "基於維護婚姻與家庭關係，甲得提起課予義務訴訟尋求救濟", "因配偶經營共同生活之婚姻自由受侵害，甲得對該拒絕處分提起撤銷訴訟尋求救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00099', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '關於因公共設施設置或管理有欠缺，人民請求國家賠償之敘述，下列何者錯誤？', '["賠償義務機關，係指公共設施之管理機關", "管理機關，係指法令所定之管理機關或依法代為管理之機關", "設施雖非由國家設置，但事實上由其管理，並直接供公共或公務目的使用，仍屬國家賠償法所稱之 公共設施", "公共設施因設置或管理，致人民人身自由受損害者，國家不負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00100', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["國家賠償請求權人，只能請求所受損害，不得請求其所失利益", "國家負損害賠償責任者，應以金錢為之。但以回復原狀為適當者，得依請求，回復損害發生前原狀", "國家賠償之請求權，自損害發生時起，因2年間不行使而消滅", "外國人為被害人時，不得請求國家賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00101', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '關於國家賠償法所規定之公務員國家賠償責任，下列敘述何者正確？', '["給付行政措施，不生公務員國家賠償責任", "受委託行使公權力者，於行使公權力時，亦適用公務員國家賠償責任", "為求人民權利保障之完整性，縱使公務員並無故意或過失，亦構成公務員國家賠償責任", "為使人民權利獲得全面性之保障，故公務員之不法行為與損害發生間，不以具有因果關係為必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00102', 'pukao-d592fc58', 'pukao-d592fc58-moex-113-d1a761c9', 'sub-pukao-d592fc58-02', NULL, 'single_choice', '有關行政裁量，下列敘述何者正確？', '["主管機關基於對外國人原國籍之厭惡，否准其歸化申請，乃裁量之濫用", "行政機關於訂定裁罰基準後，即不得於個案裁處時再為裁量", "法規授予行政機關裁量時，法院即不得審查該裁量決定", "法規授予行政機關裁量時，上級機關亦不得訂定統一之裁量基準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00103', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'essay', '甲擬於其身體健康、意識清楚之際，先決定往後萬一有失智或意識不清
時，自己各種身上照顧及財產相關事宜之處理，也避免將來子女間意見
不合之問題發生，故與女兒乙約定其為第一順位之受任人，如乙先於甲
死亡或乙自己無法視事時，則由兒子丙為第二順位之受任人。試問此種
約定具有何種意義，及其效力如何？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00104', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'essay', 'A銀行之理財專員甲常給予乙各種投資建議，因此深得客戶乙信賴，故
乙遂將存摺印章交給甲保管，以便於甲直接為乙進行各項投資。嗣後甲
因某次操作國外期貨發生鉅額損失，甲遂持乙之存摺印鑑向同銀行之行
員丙請領乙活期存款帳戶中的一百萬元，並向丙聲稱係乙託其代領。而
甲取得該款項後將該筆資金作為填補自己之投資損害，甲自認往後如果
投資有賺錢再將錢存回乙帳戶中即可。嗣乙因資金需求上網查詢存款餘
額後才發現被甲盜領活期存款一百萬元，乙遂訴請 A銀行與甲負返還一
百萬元之責任；而 A銀行主張，行員丙之付款屬於向善意占有人清償，
故銀行已經免責，應由甲自負其責，作為抗辯，試問 A銀行是否需與甲
對乙負連帶責任？請附具理由說明之。（30 分）
42050', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00105', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '下列何種屬於適用2年短期消滅時效之請求權？', '["借款返還請求權", "房屋出租人每月之租金請求權", "所有物返還請求權", "商人所供給商品之代價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00106', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲將屬於乙所有之A動產，以自己名義讓與知情之丙。該讓與A動產之行為效力如何？', '["效力未定", "無效", "得撤銷", "有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL)
